document.addEventListener("DOMContentLoaded", function() {
  // 1. Aktualny rok
  const year = document.getElementById("js-current-year");
  if (year) {
    year.textContent = new Date().getFullYear();
  }

  // 2. Logika Navbara
  const navbar = document.querySelector(".navbar");
  const navbarCollapse = document.getElementById("navbarSupportedContent");

  function updateNavbar() {
    const isScrolled = window.scrollY > 5;
    const isMenuOpen = navbarCollapse.classList.contains("show");

    // Jeśli strona jest przescrollowana LUB menu jest otwarte -> Navbar Dark
    if (isScrolled || isMenuOpen) {
      navbar.classList.add("navbar-dark");
      navbar.classList.remove("navbar-light");
    } else {
      // Tylko jeśli góra strony I menu zamknięte -> Navbar Light
      navbar.classList.add("navbar-light");
      navbar.classList.remove("navbar-dark");
    }
  }

  // Nasłuchiwanie scrolla
  window.addEventListener("scroll", updateNavbar);

  // Logika dla Bootstrap Collapse (hamburger menu)
  // Ponieważ używasz Bootstrapa, musimy reagować na klasy dodawane przez niego
  
  // To wyłapie moment kliknięcia w hamburgera (pobieramy stany z Bootstrapowych eventów)
  $(navbarCollapse).on('show.bs.collapse', function () {
    navbar.classList.add("navbar-dark");
    navbar.classList.remove("navbar-light");
  });

  $(navbarCollapse).on('hidden.bs.collapse', function () {
    // Sprawdzamy czy po zamknięciu nie jesteśmy na górze strony
    updateNavbar();
  });
});
